import React, { useState, useEffect } from 'react';
import { standingsAPI } from '../services/api';
import './Standings.css';

export default function Standings() {
  const [standings, setStandings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchStandings();
  }, []);

  const fetchStandings = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await standingsAPI.getStandings();
      setStandings(response.data.standings);
    } catch (err) {
      setError('Lỗi khi tải bảng xếp hạng: ' + (err.response?.data?.error || err.message));
    } finally {
      setLoading(false);
    }
  };

  const getMedalEmoji = (rank) => {
    switch(rank) {
      case 1: return '🥇';
      case 2: return '🥈';
      case 3: return '🥉';
      default: return '';
    }
  };

  return (
    <div className="standings-container">
      <div className="standings-header">
        <h1>⭐ Bảng Xếp Hạng Động</h1>
        <button className="btn btn-refresh" onClick={fetchStandings} disabled={loading}>
          {loading ? '⏳ Đang cập nhật...' : '🔄 Cập nhật'}
        </button>
      </div>

      {error && <div className="alert alert-error">❌ {error}</div>}

      {loading ? (
        <div className="loading">⏳ Đang tải dữ liệu...</div>
      ) : standings.length === 0 ? (
        <div className="no-data">📭 Chưa có dữ liệu xếp hạng</div>
      ) : (
        <div className="standings-wrapper">
          <div className="standings-table-container">
            <table className="standings-table">
              <thead>
                <tr>
                  <th className="rank-col">HB</th>
                  <th className="team-col">Đội Bóng</th>
                  <th className="city-col">Thành Phố</th>
                  <th className="coach-col">HLV</th>
                  <th className="record-col">Thắng</th>
                  <th className="record-col">Thua</th>
                  <th className="total-col">Tổng</th>
                  <th className="winrate-col">Tỷ Lệ %</th>
                </tr>
              </thead>
              <tbody>
                {standings.map((team) => (
                  <tr key={team._id} className={`rank-${team.rank}`}>
                    <td className="rank-cell">
                      {getMedalEmoji(team.rank)} 
                      <span className="rank-num">{team.rank}</span>
                    </td>
                    <td className="team-name">{team.name}</td>
                    <td className="team-city">{team.city}</td>
                    <td className="team-coach">{team.coach}</td>
                    <td className="record wins">{team.wins}</td>
                    <td className="record losses">{team.losses}</td>
                    <td className="record total">{team.totalGames}</td>
                    <td className="winrate">
                      <div className="winrate-bar">
                        <div 
                          className="winrate-fill" 
                          style={{ width: `${Math.max(10, team.winRate)}%` }}
                        ></div>
                        <span className="winrate-text">{team.winRate}%</span>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Stats Cards */}
          <div className="stats-cards-grid">
            {standings[0] && (
              <div className="stat-card leader">
                <div className="stat-icon">🥇</div>
                <div className="stat-content">
                  <h3>Dẫn Đầu</h3>
                  <p className="stat-team">{standings[0].name}</p>
                  <p className="stat-value">{standings[0].winRate}%</p>
                </div>
              </div>
            )}

            {standings[1] && (
              <div className="stat-card second">
                <div className="stat-icon">🥈</div>
                <div className="stat-content">
                  <h3>Thứ Hai</h3>
                  <p className="stat-team">{standings[1].name}</p>
                  <p className="stat-value">{standings[1].winRate}%</p>
                </div>
              </div>
            )}

            {standings[2] && (
              <div className="stat-card third">
                <div className="stat-icon">🥉</div>
                <div className="stat-content">
                  <h3>Thứ Ba</h3>
                  <p className="stat-team">{standings[2].name}</p>
                  <p className="stat-value">{standings[2].winRate}%</p>
                </div>
              </div>
            )}

            <div className="stat-card total">
              <div className="stat-icon">📊</div>
              <div className="stat-content">
                <h3>Tổng Thể</h3>
                <p className="stat-team">{standings.length} đội</p>
                <p className="stat-value">{standings.reduce((sum, t) => sum + t.totalGames, 0)} trận</p>
              </div>
            </div>
          </div>

          {/* Last Updated */}
          <div className="last-updated">
            🕐 Cập nhật lúc: {new Date().toLocaleTimeString('vi-VN')}
          </div>
        </div>
      )}
    </div>
  );
}
